import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save, Plus, Trash2, Copy } from 'lucide-react';
import { getPresupuestoOnline, createPresupuestoOnline, updatePresupuestoOnline, deletePresupuestoOnline } from '../../services/api';
import Loading from '../common/Loading';

const FILAS_FIJAS = [
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
  { detalle: 'LONGITUD', es_unidad: false },
];

const ESPECIALES = [
  { detalle: 'ZÓCALOS', es_unidad: false },
  { detalle: 'APERTURA + PEGADO PILETA', es_unidad: true },
  { detalle: 'APERTURA PILETA APOYO', es_unidad: true },
  { detalle: 'MENSULAS', es_unidad: true },
  { detalle: 'APERTURA ANAFE', es_unidad: true },
  { detalle: 'TERMINACIÓN', es_unidad: true },
  { detalle: 'PILETA MOD', es_unidad: true },
];

function emptyItem(detalle = 'LONGITUD', es_unidad = false) {
  return { detalle, largo: 0, ancho: 0, m2: 0, es_unidad, cantidad: 1, precio_unitario: 0, subtotal: 0 };
}

export default function PresupuestoOnlineForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = !!id;
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [items, setItems] = useState(FILAS_FIJAS.map((f) => emptyItem(f.detalle, f.es_unidad)));
  const [especiales, setEspeciales] = useState(ESPECIALES.map((e) => emptyItem(e.detalle, e.es_unidad)));
  const [cliente, setCliente] = useState('');
  const [tipoObra, setTipoObra] = useState('');
  const [fecha, setFecha] = useState(new Date().toISOString().slice(0, 10));
  const [conversion, setConversion] = useState(1.00);
  const [totalGeneral, setTotalGeneral] = useState(0);
  const [totalFinal, setTotalFinal] = useState(0);

  useEffect(() => {
    if (isEdit) {
      getPresupuestoOnline(id).then((res) => {
        const d = res.data;
        setCliente(d.cliente || '');
        setTipoObra(d.tipo_obra || '');
        setFecha(d.fecha || new Date().toISOString().slice(0, 10));
        setConversion(d.conversion || 1.00);
        if (d.items && d.items.length > 0) {
          const normales = d.items.filter((i) => !i.es_unidad);
          const esp = d.items.filter((i) => i.es_unidad);
          const filledNormales = FILAS_FIJAS.map((f, idx) => normales[idx] || emptyItem(f.detalle, f.es_unidad));
          const filledEsp = ESPECIALES.map((e, idx) => esp[idx] || emptyItem(e.detalle, e.es_unidad));
          setItems(filledNormales);
          setEspeciales(filledEsp);
        }
        setLoading(false);
      });
    }
  }, [id, isEdit]);

  const updateItem = (idx, field, value, isEspecial) => {
    const list = isEspecial ? [...especiales] : [...items];
    list[idx] = { ...list[idx], [field]: value };

    if (field === 'largo' || field === 'ancho') {
      const largo = Number(list[idx].largo) || 0;
      const ancho = Number(list[idx].ancho) || 0;
      if (!list[idx].es_unidad) {
        list[idx].m2 = Math.round(largo * ancho * 10000) / 10000;
      }
    }

    const m2 = list[idx].m2 || 0;
    const cant = Number(list[idx].cantidad) || 1;
    const pu = Number(list[idx].precio_unitario) || 0;
    if (list[idx].es_unidad) {
      list[idx].subtotal = Math.round(cant * pu * 100) / 100;
    } else if (m2 > 0) {
      list[idx].subtotal = Math.round(m2 * cant * pu * 100) / 100;
    } else {
      list[idx].subtotal = Math.round(cant * pu * 100) / 100;
    }

    if (isEspecial) setEspeciales(list);
    else setItems(list);

    recalcTotales();
  };

  const recalcTotales = () => {
    let total = 0;
    items.forEach((i) => { total += i.subtotal || 0; });
    especiales.forEach((i) => { total += i.subtotal || 0; });
    setTotalGeneral(Math.round(total * 100) / 100);
    setTotalFinal(Math.round(total * (conversion || 1) * 100) / 100);
  };

  useEffect(() => {
    recalcTotales();
  }, [conversion]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const allItems = [...items, ...especiales];
      const payload = {
        cliente,
        tipo_obra: tipoObra,
        fecha,
        items: allItems,
        total_general: totalGeneral,
        conversion: Number(conversion) || 1.00,
        total_final: totalFinal,
      };
      if (isEdit) {
        await updatePresupuestoOnline(id, payload);
      } else {
        await createPresupuestoOnline(payload);
      }
      navigate('/presupuestos-online');
    } catch (err) {
      alert('Error al guardar');
    } finally {
      setSaving(false);
    }
  };

  const generarTextoWhatsApp = () => {
    const lineas = [];
    lineas.push('🏛️ AFAMAR - MÁRMOLES & GRANITOS');
    lineas.push('📍 LA PLATA, BS AS');
    if (cliente) lineas.push(`👤 Cliente: ${cliente}`);
    if (tipoObra) lineas.push(`🏗️ Obra: ${tipoObra}`);
    if (fecha) lineas.push(`📅 Fecha: ${fecha}`);
    lineas.push('');
    lineas.push('━━━ PRESUPUESTO ━━━');
    lineas.push('');
    [...items, ...especiales].forEach((i) => {
      if (i.subtotal > 0) {
        let texto = `• ${i.detalle}`;
        if (i.es_unidad) {
          texto += ` | Cant: ${i.cantidad}`;
        } else if (i.m2 > 0) {
          texto += ` | ${i.largo}×${i.ancho} = ${i.m2.toFixed(4)} m²`;
          if (i.cantidad > 1) texto += ` × ${i.cantidad}`;
        }
        if (i.precio_unitario > 0) texto += ` | $${i.precio_unitario.toFixed(2)}/u`;
        texto += ` = $${i.subtotal.toLocaleString('es-AR', { minimumFractionDigits: 2 })}`;
        lineas.push(texto);
      }
    });
    lineas.push('');
    lineas.push(`💰 TOTAL: $${totalGeneral.toLocaleString('es-AR', { minimumFractionDigits: 2 })}`);
    if (conversion !== 1) {
      lineas.push(`🔄 CONVERSIÓN: ×${conversion}`);
      lineas.push(`🔥 TOTAL FINAL: $${totalFinal.toLocaleString('es-AR', { minimumFractionDigits: 2 })}`);
    }
    lineas.push('');
    lineas.push('📲 Consultas al WhatsApp');
    return lineas.join('\n');
  };

  const copiarWhatsApp = () => {
    navigator.clipboard.writeText(generarTextoWhatsApp());
    alert('Texto copiado al portapapeles. Pegalo en WhatsApp.');
  };

  const inputStyle = { width: '100%', padding: '4px 6px', border: '1px solid #d1d5db', borderRadius: 4, fontSize: 13, textAlign: 'right', boxSizing: 'border-box' };
  const inputTextStyle = { ...inputStyle, textAlign: 'left' };
  const cellStyle = { padding: '3px 4px' };

  if (loading) return <Loading />;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <h1 style={{ fontSize: 24, fontWeight: 700 }}>
          {isEdit ? `Editar Presupuesto en Línea` : 'Nuevo Presupuesto en Línea'}
        </h1>
      </div>

      <form onSubmit={handleSubmit}>
        {/* Encabezado */}
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 14, fontWeight: 700, color: '#b91c1c', marginBottom: 12 }}>
            🏛️ AFAMAR - MÁRMOLES & GRANITOS — LA PLATA, BS AS
          </div>
          <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap' }}>
            <div className="form-group" style={{ flex: 1, minWidth: 200 }}>
              <label>CLIENTE / EMPRESA</label>
              <input className="input" value={cliente} onChange={(e) => setCliente(e.target.value)} placeholder="Nombre del cliente" />
            </div>
            <div className="form-group" style={{ flex: 1, minWidth: 200 }}>
              <label>TIPO DE OBRA</label>
              <input className="input" value={tipoObra} onChange={(e) => setTipoObra(e.target.value)} placeholder="Ej: Cocina, Baño" />
            </div>
            <div className="form-group" style={{ width: 160 }}>
              <label>FECHA</label>
              <input type="date" className="input" value={fecha} onChange={(e) => setFecha(e.target.value)} />
            </div>
          </div>
        </div>

        {/* Tabla de items */}
        <div className="card" style={{ marginBottom: 16, overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
            <thead>
              <tr style={{ background: '#f8fafc' }}>
                <th style={{ ...cellStyle, textAlign: 'left', width: '22%' }}>Sector / Modelo / Marca</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '10%' }}>Largo</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '10%' }}>Ancho</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '10%' }}>M² / U</th>
                <th style={{ ...cellStyle, textAlign: 'center', width: '10%' }}>Cant.</th>
                <th style={{ ...cellStyle, textAlign: 'right', width: '14%' }}>Precio Unit.</th>
                <th style={{ ...cellStyle, textAlign: 'right', width: '14%' }}>Subtotal</th>
              </tr>
            </thead>
            <tbody>
              <tr style={{ background: '#e0f2fe' }}>
                <td colSpan={7} style={{ ...cellStyle, fontWeight: 700, fontSize: 13, color: '#0369a1' }}>
                  📐 PRODUCCIÓN ESTÁNDAR
                </td>
              </tr>
              {items.map((item, idx) => (
                <tr key={idx}>
                  <td style={cellStyle}>
                    <input style={inputTextStyle} value={item.detalle} onChange={(e) => updateItem(idx, 'detalle', e.target.value, false)} />
                  </td>
                  <td style={cellStyle}>
                    <input type="number" step="any" style={inputStyle} value={item.largo || ''} onChange={(e) => updateItem(idx, 'largo', e.target.value, false)} />
                  </td>
                  <td style={cellStyle}>
                    <input type="number" step="any" style={inputStyle} value={item.ancho || ''} onChange={(e) => updateItem(idx, 'ancho', e.target.value, false)} />
                  </td>
                  <td style={{ ...cellStyle, textAlign: 'center', fontWeight: 600 }}>
                    {item.m2 > 0 ? item.m2.toFixed(4) : '-'}
                  </td>
                  <td style={cellStyle}>
                    <input type="number" style={inputStyle} value={item.cantidad} onChange={(e) => updateItem(idx, 'cantidad', e.target.value, false)} min="1" />
                  </td>
                  <td style={cellStyle}>
                    <input type="number" step="any" style={inputStyle} value={item.precio_unitario || ''} onChange={(e) => updateItem(idx, 'precio_unitario', e.target.value, false)} />
                  </td>
                  <td style={{ ...cellStyle, textAlign: 'right', fontWeight: 600 }}>
                    ${(item.subtotal || 0).toLocaleString('es-AR', { minimumFractionDigits: 2 })}
                  </td>
                </tr>
              ))}
              <tr style={{ background: '#fef3c7' }}>
                <td colSpan={7} style={{ ...cellStyle, fontWeight: 700, fontSize: 13, color: '#92400e' }}>
                  ✂️ CORTES Y ACCESORIOS
                </td>
              </tr>
              {especiales.map((item, idx) => (
                <tr key={idx}>
                  <td style={cellStyle}>
                    <input style={inputTextStyle} value={item.detalle} onChange={(e) => updateItem(idx, 'detalle', e.target.value, true)} />
                  </td>
                  <td style={cellStyle}></td>
                  <td style={cellStyle}></td>
                  <td style={{ ...cellStyle, textAlign: 'center', fontWeight: 600, color: '#b91c1c' }}>
                    U
                  </td>
                  <td style={cellStyle}>
                    <input type="number" style={inputStyle} value={item.cantidad} onChange={(e) => updateItem(idx, 'cantidad', e.target.value, true)} min="1" />
                  </td>
                  <td style={cellStyle}>
                    <input type="number" step="any" style={inputStyle} value={item.precio_unitario || ''} onChange={(e) => updateItem(idx, 'precio_unitario', e.target.value, true)} />
                  </td>
                  <td style={{ ...cellStyle, textAlign: 'right', fontWeight: 600 }}>
                    ${(item.subtotal || 0).toLocaleString('es-AR', { minimumFractionDigits: 2 })}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Totales y conversión */}
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 24, alignItems: 'center', flexWrap: 'wrap' }}>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontSize: 14, color: '#64748b' }}>TOTAL GRAL</div>
              <div style={{ fontSize: 22, fontWeight: 700 }}>${totalGeneral.toLocaleString('es-AR', { minimumFractionDigits: 2 })}</div>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <div style={{ fontSize: 14, color: '#64748b' }}>CONVERSIÓN</div>
              <input type="number" step="0.01" style={{ width: 80, padding: '6px 8px', border: '1px solid #d1d5db', borderRadius: 4, fontSize: 16, fontWeight: 700, textAlign: 'center' }}
                value={conversion} onChange={(e) => setConversion(Number(e.target.value) || 1)} />
            </div>
            <div style={{ textAlign: 'right', background: '#dc2626', color: 'white', padding: '8px 20px', borderRadius: 8 }}>
              <div style={{ fontSize: 13, fontWeight: 600 }}>TOTAL FINAL</div>
              <div style={{ fontSize: 24, fontWeight: 800 }}>${totalFinal.toLocaleString('es-AR', { minimumFractionDigits: 2 })}</div>
            </div>
          </div>
        </div>

        {/* Botones */}
        <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end', flexWrap: 'wrap' }}>
          <button type="button" className="btn btn-success" onClick={copiarWhatsApp} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/></svg>
            Exportar para WhatsApp
          </button>
          <button type="button" className="btn btn-outline" onClick={() => navigate('/presupuestos-online')}>Cancelar</button>
          <button type="submit" className="btn btn-primary" disabled={saving} style={{ background: '#b91c1c' }}>
            <Save size={16} /> {saving ? 'GUARDANDO...' : 'GUARDAR'}
          </button>
        </div>
      </form>
    </div>
  );
}
